code = """import json

# Get the emergency/FEMA projects from previous execution
emergency_fema_projects = locals()["var_functions.execute_python:32"]

if isinstance(emergency_fema_projects, str):
    with open(emergency_fema_projects) as f:
        emergency_fema_projects = json.load(f)

# Sort by amount descending
emergency_fema_projects.sort(key=lambda x: int(x['Amount']), reverse=True)

# Create formatted output
output_lines = []
output_lines.append("EMERGENCY/FEMA PROJECTS")
output_lines.append("=" * 80)
output_lines.append("")

for project in emergency_fema_projects:
    output_lines.append(f"Project: {project['Project_Name']}")
    output_lines.append(f"Funding Source: {project['Funding_Source']}")
    output_lines.append(f"Amount: ${int(project['Amount']):,}")
    output_lines.append(f"Status: {project['Status'].title()}")
    output_lines.append("-" * 80)
    output_lines.append("")

output_lines.append(f"Total Projects Found: {len(emergency_fema_projects)}")
output_lines.append("=" * 80)

final_text = "\n".join(output_lines)
print(final_text)

result = final_text
print('__RESULT__:')
print(result)"""

